+Tensor ns_malloc_tensor(Shape shape, DLDataType dtype, int device_id) {
+  return Tensor::FromNDAlloc(NVSHMEMNDAlloc(), tvm::ffi::Shape(shape), dtype,
+                             DLDevice{kDLCUDA, device_id});
+}
